#include <iostream>

int main()
{
    int grid[3][4]{};

    for (int r = 0; r < 3; ++r)
        for (int c = 0; c < 4; ++c)
            std::cin >> grid[r][c];

    for (int r = 0; r < 3; ++r)
    {
        int sum = 0;
        for (int c = 0; c < 4; ++c)
            sum += grid[r][c];
        std::cout << sum << '\n';
    }

    return 0;
}

