solution_code:
#include <iostream>

int rowMax(int row[], int cols)
{
    int best = row[0];
    for (int c = 1; c < cols; ++c)
        if (row[c] > best)
            best = row[c];
    return best;
}

int main()
{
    int mat[2][5]{};
    for (int r = 0; r < 2; ++r)
        for (int c = 0; c < 5; ++c)
            std::cin >> mat[r][c];

    for (int r = 0; r < 2; ++r)
        std::cout << "Row " << r << ": " << rowMax(mat[r], 5) << '\n';

    return 0;
}
